<template>
  <el-container style="height:100%">
    <el-main>
      <el-row :gutter="0">
      <el-col :span="14" style="padding:0px 10px">
        <el-descriptions v-for="(item, index) in statusData.systemDataList" :title="item.devdesp" :key="index">
          <el-descriptions-item label="devid">{{item.devid}}</el-descriptions-item>
          <el-descriptions-item label="devname">{{item.devname}}</el-descriptions-item>
          <el-descriptions-item label="devtype">{{item.devtype}}</el-descriptions-item>
          <el-descriptions-item label="devdesp">{{item.devdesp}}</el-descriptions-item>
          <el-descriptions-item label="timestamp">{{item.timestamp}}</el-descriptions-item>
          <el-descriptions-item label="timestampstr">{{item.timestampstr}}</el-descriptions-item>
          <el-descriptions-item label="cpuUsed">{{Math.trunc(item.cpuUsed*10000)/100}}&nbsp;%</el-descriptions-item>
          <el-descriptions-item label="cpuUser">{{Math.trunc(item.cpuUser*10000)/100}}&nbsp;%</el-descriptions-item>
          <el-descriptions-item label="cpuSys">{{Math.trunc(item.cpuSys*10000)/100}}&nbsp;%</el-descriptions-item>
          <el-descriptions-item label="cpuIdle">{{Math.trunc(item.cpuIdle*10000)/100}}&nbsp;%</el-descriptions-item>
          <el-descriptions-item label="cpuWait">{{Math.trunc(item.cpuWait*10000)/100}}&nbsp;%</el-descriptions-item>
          <el-descriptions-item label="memTotal">{{Math.trunc(item.memTotal / 1024.0 / 1024.0 * 100) / 100}}&nbsp;Gb</el-descriptions-item>
          <el-descriptions-item label="memFree">{{Math.trunc(item.memFree/1024.0/1024.0*100)/100}}&nbsp;Gb</el-descriptions-item>
          <el-descriptions-item label="memUsed">{{Math.trunc(item.memUsed/1024.0/1024.0*100)/100}}&nbsp;Gb</el-descriptions-item>
          <el-descriptions-item label="memBuffers">{{Math.trunc(item.memBuffers/1024.0/1024.0*100)/100}}&nbsp;Gb</el-descriptions-item>
          <el-descriptions-item label="memCached">{{Math.trunc(item.memCached/1024.0/1024.0*100)/100}}&nbsp;Gb</el-descriptions-item>

          <el-descriptions-item label="diskTotal">{{Math.trunc(item.diskTotal/1024.0/1024.0/1024.0*100)/100}}&nbsp;Gb</el-descriptions-item>
          <el-descriptions-item label="diskUsed">{{Math.trunc(item.diskUsed/1024.0/1024.0/1024.0*100)/100}}&nbsp;Gb</el-descriptions-item>
        </el-descriptions>
      </el-col>

      <el-col :span="10" style="height:100%;">
        <div style="width:98%;height:100%;border:1px solid gray;margin:0px 0px;text-align:left">
          <pre>{{textarea}}</pre>
        </div>
      </el-col>

      </el-row>
    </el-main>
    <el-footer height="0px"></el-footer>
  </el-container>
</template>

<script>
import proto from "../assets/sdkapi_pb.js"
export default {
  name: 'SystemPage',
  props: {
    msg: String
  },
  data() {
    this.request_sequence = 0;
    this.dayjs = require("dayjs");
    return {
      statusData: {},
      commandSelect: "",
      devTypeSelect: "",
      devSelect: "",
      devSelectList: "",
      textarea: "",
      tableData: [],
    };
  },
  mounted() {
    var that = this;
    this.$bus.$on("websocket-data-received", function(d) {
      var data = d.data;
      if (data.command == proto.Command.CMD_UPDATE_STATUS_DATA) {
        console.log(data);
        that.updateStatusData(data, d.size);
      }
    });
  },
  methods: {
    handleSelect(key, keyPath) {
      console.log(key, keyPath);
    },
    onClickHistory(row) {
      var request = new proto.Request();
      request.setCommand(proto.Command.CMD_GET_HISTORY_DATA);
      var param_data = request.addParamData();
      param_data.setKey("data_type");
      param_data.setVal(row.devtype);
      param_data = request.addParamData();
      param_data.setKey("devid");
      param_data.setVal(row.devid + "");
      var d = request.serializeBinary();                  // 序列化
      console.log("request history: id: " + row.did);
      this.$bus.$emit("websocket-send-data", {data:d});
    },
    onClickUpdate(row) {
      var request = new proto.Request();
      request.setCommand(proto.Command.CMD_GET_STATUS_DATA);
      var param_data = request.addParamData();
      param_data.setKey("data_type");
      param_data.setVal(row.devtype);
      param_data = request.addParamData();
      param_data.setKey("devid");
      param_data.setVal(row.devid + "");
      var d = request.serializeBinary();                  // 序列化
      console.log("request history: id: " + row.did);
      this.$bus.$emit("websocket-send-data", {data:d});
    },
    onDevTypeChange(d) {
      for (var i = 0; i < this.devList.length; i++) {
        if (this.devList[i].value == d) {
          this.devSelectList = this.devList[i].data;
          break;
        }
      }
      console.log(d, this.devSelectList);
    },
    onDevSelectChange(d) {
      console.log(d);
    },
    onClickDetail(d) {
      this.textarea = d.responseData;
      this.statusData = d.statusData;
    },
    onSubmit() {
      console.log("submit: command: " + this.commandSelect + ", devtype: " + this.devTypeSelect + ", dev: " + this.devSelect);

      var header = new proto.Header();
      header.setUserdata("debugger");
      header.setRequestSequence(this.request_sequence);
      var request = new proto.Request();
      request.setCommand(this.commandSelect);
      header = request.setHeader(header);
      var param_data = request.addParamData();
      param_data.setKey("data_type");
      param_data.setVal(this.devTypeSelect);
      param_data = request.addParamData();
      param_data.setKey("devid");
      param_data.setVal(this.devSelect + "");
      var d = request.serializeBinary();
      this.$bus.$emit("websocket-send-data", {data:d});

      var dd = {
        index: this.tableData.length + 1,
        request_sequence: this.request_sequence,
        startTime: Date.now(),
        startTimeStr: '',
        endTime: '',
        endTimeStr: '',
        responseData: null,
      };
      this.tableData.push(dd);
      this.request_sequence++;
    },
    updateDataList(d) {
      console.log("update data list: ", d);
      if (!d || !d.dataList || !d.dataList.dataItemList) {
        console.error("updata data list error: ", d);
      }
      d.dataList.dataItemList.forEach(v => {
        var devtype = v.devtype;
        for (var i = 0; i < this.devList.length; i++) {
          if (this.devList[i].value == devtype) {
            this.devList[i].data.push(v);
          }
        }
      });
      this.devList.sort(function(a, b) {
        return b.data.length - a.data.length;
      });
      this.devList.forEach(v => {
        v.data.sort(function(a, b) { return a.devid - b.devid; });
      });
    },
    updateStatusData(d, size) {
      this.textarea = d;
      this.statusData = d.statusData;
      this.statusData.systemDataList.forEach(v => {
        var t1 = this.dayjs(v.timestamp);
        v.timestampstr = t1.format("YYYY-MM-DD HH:mm:ss")  + "." + t1.millisecond();
      });
    },
    updateChart(d) {
    }
  }
}
</script>

